  to { opacity: 1; transform: scale(1); }
}

/* Utility classes */
.animate-breathe { animation: breathe 6s ease-in-out infinite; }
.animate-breathe-slow { animation: breathe-slow 10s ease-in-out infinite; }
.animate-float { animation: float 8s ease-in-out infinite; }
.animate-drift { animation: drift 20s ease-in-out infinite; }
.animate-gradient { 
  background-size: 200% 200%;
  animation: gradient-shift 8s ease-in-out infinite; 
}
.animate-reveal { animation: reveal-up 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards; }

/* Staggered delays */
.delay-100 { animation-delay: 100ms; }
.delay-200 { animation-delay: 200ms; }
.delay-300 { animation-delay: 300ms; }
.delay-400 { animation-delay: 400ms; }
.delay-500 { animation-delay: 500ms; }
.delay-600 { animation-delay: 600ms; }
.delay-700 { animation-delay: 700ms; }
.delay-800 { animation-delay: 800ms; }

/* ============================================
   COMPONENT STYLES
   ============================================ */

/* Glass card */
.glass-card {
  background: rgba(255, 255, 255, 0.6);
  backdrop-filter: blur(20px) saturate(1.8);
  -webkit-backdrop-filter: blur(20px) saturate(1.8);
  border: 1px solid rgba(255, 255, 255, 0.4);
  border-radius: 24px;
  box-shadow: 
    0 4px 6px rgba(0,0,0,0.02),
    0 12px 24px rgba(0,0,0,0.04),
    inset 0 1px 0 rgba(255,255,255,0.6);
}

/* Organic blob shape */
.organic-blob {
  border-radius: 30% 70% 70% 30% / 30% 30% 70% 70%;
}

/* Text gradient */
.text-gradient-primary {
  background: linear-gradient(135deg, var(--color-primary-500), var(--color-sage-500));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Grain overlay */
.grain::after {
  content: '';
  position: absolute;
  inset: 0;
  opacity: 0.03;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  pointer-events: none;
  z-index: 1;
}

/* Editorial quote styling */
.editorial-quote {
  position: relative;
  padding-left: 2rem;
}
.editorial-quote::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  background: linear-gradient(to bottom, var(--color-primary-400), var(--color-coral-400));
  border-radius: 2px;
}

/* Hover underline animation */
.hover-underline {
  position: relative;
}
.hover-underline::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--color-primary-500);
  transition: width 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}
.hover-underline:hover::after {
  width: 100%;
}

