  projectId,
  dataset,
  apiVersion,
  useCdn: true,
})

const builder = createImageUrlBuilder(client)
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function urlFor(source: any) {
  return builder.image(source)
}

import { groq } from 'next-sanity'
// Full post (for blog post page) export const postBySlugQuery = groq` *[_type == "post" && slug.current == $slug][0] { _id, title, "slug": slug.current, excerpt, body, category, tags, author, publishedAt, mainImage { ..., "url": asset->url, alt }, seoDescription, relatedPosts[]-> { _id, title, "slug": slug.current, excerpt, category, publishedAt, mainImage { "url": asset->url, alt } } } `
// Listing (all posts, newest first) export const allPostsQuery = groq` *[_type == "post"] | order(publishedAt desc) { _id, title, "slug": slug.current, excerpt, category, tags, author, publishedAt, mainImage { "url": asset->url, alt } } `
// Slugs (for static generation) export const allPostSlugsQuery = groq` *[_type == "post"] { "slug": slug.current } `

import { type SchemaTypeDefinition } from 'sanity'
import { postType } from './post'

export const schema: { types: SchemaTypeDefinition[] } = {
  types: [postType],
}

import type { PortableTextBlock } from '@portabletext/types'
export interface SanityPost { _id: string title: string slug: string excerpt: string body?: PortableTextBlock[] category: string tags: string[] author: string publishedAt: string mainImage?: { url: string; alt?: string } seoDescription?: string relatedPosts?: SanityRelatedPost[] }
export interface SanityRelatedPost { _id: string title: string slug: string excerpt: string category: string publishedAt: string mainImage?: { url: string; alt?: string } }
